const items = $input.all();
let accounts = [], mapping = [];

if (items.length >= 2) {
  const accountsRes = items.find(i => i.json?.accounts) || items[0];
  const mappingRes = items.find(i => i.json?.mapping) || items[1];
  accounts = accountsRes.json?.accounts || [];
  mapping = mappingRes.json?.mapping || [];
} else if (items.length === 1) {
  const single = items[0].json || {};
  accounts = single.accounts || [];
  mapping = single.mapping || [];
}

if (accounts.length === 0) return [];

const byId = {};
mapping.forEach(m => { byId[m.meta_account_id] = m; byId['act_' + m.meta_account_id] = m; });
const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toISOString().split('T')[0];
return accounts.map(a => {
  const id = a.id || ('act_' + (a.account_id || ''));
  const m = byId[id] || {};
  return { json: { account_id: id, account_name: a.name || a.id, client_id: m.client_id || null, owner_type: m.owner_type || 'adventure', _date: dateStr } };
});

const item = $input.item?.json || $input.first()?.json || {};
const account = item.account_id != null ? item : {};
const insights = item.insights || [];
const ins = Array.isArray(insights) ? insights[0] : insights || {};
const date = account._date || new Date().toISOString().split('T')[0];
const spend = ins?.spend != null ? parseFloat(ins.spend) : null;
const impressions = ins?.impressions != null ? parseInt(ins.impressions, 10) : null;
const clicks = ins?.clicks != null ? parseInt(ins.clicks, 10) : null;
const teveVeiculacao = (impressions && impressions > 0) || (spend && spend > 0) || (clicks && clicks > 0);
if (!teveVeiculacao) return [];
const row = { date, account_id: account.account_id, account_name: account.account_name || null, client_id: account.client_id || null, owner_type: account.owner_type || 'adventure', spend, impressions, clicks, conversions: null };
return [{ json: { rows: [row] } }];

const s = $input.first()?.json || {};
const n = s.distinct_dates || 0;
const minDays = 1;
if (n < minDays) return [];
const title = 'Lara (Meta Ads) — resumo ' + (s.max_date || '');
return [{ json: { title, min_date: s.min_date, max_date: s.max_date, distinct_dates: n } }];

const s = $input.first()?.json || {};
const min = s.min_date || '';
const max = s.max_date || '';
const n = s.distinct_dates || 0;
const title = s.title || ('Lara (Meta Ads) — resumo ' + max);
const prompt = `Período de análise Meta Ads: ${min} a ${max} (${n} dias distintos).\n\nUse suas ferramentas: (1) get_context_docs para obter o conhecimento da empresa/C-Suite; (2) get_lara_memory para sua memória recente; (3) get_daily_data com from=${min} e to=${max} para os dados de veiculação.\n\nProduza um relatório em markdown com: (1) Métricas e resumo do que rodou (tabela por conta, totais); (2) Análise Lara: resumo executivo, insights e 3-5 recomendações. Separe contas cliente (owner_type=cliente) e Adventure (owner_type=adventure).`;
return [{ json: { prompt, title, sessionId: 'lara-meta-' + max } }];

const agentOutput = $input.first()?.json?.output ?? $input.first()?.json?.text ?? '';
const title = $('Prepare Lara Prompt').first()?.json?.title ?? 'Lara (Meta Ads) — resumo';
return [{ json: { title, content: agentOutput } }];
